INSERT INTO "public"."dev_prayers" ("lesson_id", "role", "text_content", "display_order") VALUES
('5a1b3dba-789c-4d07-933c-d73e75bf957a', 'Pai', 'Senhor, ajuda-nos a ter coragem para reconhecer nossos erros. Dá aos nossos filhos um coração que busca sempre a verdade.', 1),
('5a1b3dba-789c-4d07-933c-d73e75bf957a', 'Filho', 'Deus, perdoa-me pelas vezes que agi errado e tive medo de admitir. Ajuda-me a ser sempre honesto com meus pais.', 2),
('5a1b3dba-789c-4d07-933c-d73e75bf957a', 'Juntos', 'Obrigado por nos receberes sempre com amor quando voltamos a Ti. Ensina-nos a perdoar uns aos outros também.', 3),
('5a27e7cd-00d1-44c0-9fb5-c953ced72d0c', 'Individual', 'Senhor, ajuda-me a edificar a muralha do domínio próprio em meu coração. Que eu não seja escravo dos meus impulsos, mas um servo fiel da Tua vontade. Dá-me sabedoria para silenciar quando a ira tentar falar e força para agir com temperança em cada situação do meu dia. Que o meu governo pessoal seja um reflexo do Teu governo em minha vida.', 1),
('5a29a96b-002c-477a-b64c-112ef6c5b5d4', 'Pai', 'Senhor, ajuda-nos a honrar as autoridades e o próximo, mesmo diante de injustiças. Ensina-nos a agir com integridade nos momentos em que ninguém nos observa.', 1),
('5a29a96b-002c-477a-b64c-112ef6c5b5d4', 'Filho', 'Deus, dá-me coragem para ser diferente na escola e não ceder à pressão de humilhar os outros. Que eu saiba escolher o caminho do respeito sempre.', 2),
('5a29a96b-002c-477a-b64c-112ef6c5b5d4', 'Juntos', 'Pai, que nossas escolhas silenciosas reflitam o Teu caráter. Ajuda nossa família a ser um exemplo de respeito em todas as situações.', 3),
('5ad74470-6a3a-436b-a86a-95ebca649440', 'Pai', 'Senhor, ajuda-me a ser um pai que corre ao encontro do meu filho com perdão. Que minha casa seja sempre um lugar de refúgio e verdade.', 1),
('5ad74470-6a3a-436b-a86a-95ebca649440', 'Filho', 'Pai do céu, perdoa-me pelas vezes que preferi esconder meus erros. Dá-me a coragem de ser honesto, mesmo quando me sentir envergonhado.', 2),
('5ad74470-6a3a-436b-a86a-95ebca649440', 'Juntos', 'Deus, obrigado porque o Teu amor nos busca onde estivermos. Que vivamos sempre com o desejo de honrar o Teu nome em cada escolha.', 3),
('5b0058c0-dddb-4aa3-a7d5-f5cb659aa0ec', 'Pai', 'Senhor, ajuda-nos a ensinar nossos filhos o valor de perdoar. Que nossa casa seja um lugar de amor e união.', 1),
('5b0058c0-dddb-4aa3-a7d5-f5cb659aa0ec', 'Filho', 'Papai do céu, me ajude a ser um pacificador. Quero sempre fazer as pazes e tratar meus amigos com bondade.', 2),
('5b0058c0-dddb-4aa3-a7d5-f5cb659aa0ec', 'Juntos', 'Querido Deus, obrigado porque somos seus filhos. Que nossa família espalhe a sua paz por onde passar!', 3),
('5b1f5c80-3699-4646-bbf7-9826e97dfbb3', 'Pai', 'Senhor, ajuda-nos a ser pais que acolhem com amor e perdão. Que nossa casa seja sempre um porto seguro de retorno para nossos filhos.', 1),
('5b1f5c80-3699-4646-bbf7-9826e97dfbb3', 'Filho', 'Pai do céu, perdoa as minhas escolhas erradas. Dá-me coragem para admitir quando falho e a humildade de buscar consertar meus erros.', 2),
('5b1f5c80-3699-4646-bbf7-9826e97dfbb3', 'Juntos', 'Agradecemos por tua graça que nos restaura. Ajuda-nos a caminhar sempre na verdade e na confiança em ti.', 3),
('5b3f9161-9d72-416d-ae01-83e457b8258f', 'Pai', 'Senhor, agradeço pelo privilégio de ver meus filhos buscarem a verdade. Ajuda-nos a sermos sempre um porto seguro de perdão e acolhimento.', 1),
('5b3f9161-9d72-416d-ae01-83e457b8258f', 'Filho', 'Pai do Céu, dá-me coragem para admitir quando erro e não deixar que o orgulho endureça o meu coração. Ensina-me a valorizar o Teu caminho.', 2),
('5b3f9161-9d72-416d-ae01-83e457b8258f', 'Juntos', 'Deus, que o nosso lar seja um lugar de honestidade e restauração. Ajuda-nos a caminhar sempre na Tua luz e verdade.', 3),
('5b4ced90-816b-4cee-80c3-d3014888b891', 'Pai', 'Senhor, ajuda-nos a ser retos em cada decisão escondida. Que nossa família valorize mais a verdade do que a aprovação alheia.', 1),
('5b4ced90-816b-4cee-80c3-d3014888b891', 'Filho', 'Deus, dá-me coragem para escolher o caminho certo, mesmo quando ninguém estiver olhando. Ensina-me a ser alguém em quem os outros possam confiar.', 2),
('5b4ced90-816b-4cee-80c3-d3014888b891', 'Juntos', 'Pai, que nossas escolhas hoje construam um caminho de honra diante de Ti. Que sejamos sempre guiados pela Tua sabedoria, amém.', 3),
('5b726224-7b89-4b80-8866-5a2b1f1c9bc3', 'Pai', 'Senhor, ajuda-nos a valorizar mais o caráter do que as coisas que o mundo oferece. Que o nosso temor a Ti seja a nossa maior prioridade.', 1),
('5b726224-7b89-4b80-8866-5a2b1f1c9bc3', 'Filho', 'Deus, dá-me coragem para ser a mesma pessoa em todos os lugares. Que a minha conduta reflita Tua verdade em cada decisão escondida.', 2),
('5b726224-7b89-4b80-8866-5a2b1f1c9bc3', 'Juntos', 'Pai, guia nossos passos no caminho da integridade. Que o nosso bom nome seja um testemunho do Teu amor em nossas vidas.', 3),
('5b968f14-9138-43e3-8c40-7c6e3f369ed7', 'Pai', 'Senhor, ensina meu filho a ser firme como Sadraque, Mesaque e Abednego. Ajuda-o a escolher sempre o caminho que te agrada.', 1),
('5b968f14-9138-43e3-8c40-7c6e3f369ed7', 'Filho', 'Papai do Céu, por favor, me dê coragem de fazer o que é certo. Fica comigo em todos os momentos do meu dia.', 2),
('5b968f14-9138-43e3-8c40-7c6e3f369ed7', 'Juntos', 'Obrigado, Deus, porque o Senhor nunca nos abandona. Queremos ser sempre fiéis ao Senhor, não importa o que aconteça.', 3),
('5be109af-409d-4fad-85de-67814bd0d124', 'Pai', 'Papai do céu, ensina nossa família a amar a paz. Que o nosso lar seja um lugar de bondade e união.', 1),
('5be109af-409d-4fad-85de-67814bd0d124', 'Filho', 'Jesus, me ajuda a ser um pacificador hoje. Ajuda meu coração a ser gentil com meus amigos.', 2),
('5be109af-409d-4fad-85de-67814bd0d124', 'Juntos', 'Obrigado por nos chamar de Seus filhos. Queremos sempre seguir o Teu caminho de amor e mansidão.', 3),
('5c6dd376-b379-405e-972e-addbbf9efd4f', 'Pai', 'Senhor, ajuda-me a educar meu filho para ser firme em seus princípios. Que ele valorize a obediência mesmo quando ninguém o estiver observando.', 1),
('5c6dd376-b379-405e-972e-addbbf9efd4f', 'Filho', 'Deus, dá-me coragem para escolher o que é certo e bom. Ajuda-me a ser leal a Ti, mesmo quando for difícil ou solitário.', 2),
('5c6dd376-b379-405e-972e-addbbf9efd4f', 'Juntos', 'Pai, fortalece nossa casa na verdade. Que nossas escolhas privadas honrem sempre o Teu nome e glorifiquem o Teu propósito.', 3),
('5cb26733-b727-4696-89c8-335febd420a4', 'Pai', 'Senhor, dá-nos sabedoria para usar nossas palavras com prudência e temor. Que o nosso falar seja sempre temperado pela Tua graça e verdade.', 1),
('5cb26733-b727-4696-89c8-335febd420a4', 'Filho', 'Pai, ajuda-me a frear o meu impulso de dizer tudo o que penso. Ensina-me a usar minha língua apenas para edificar quem estiver ao meu redor.', 2),
('5cb26733-b727-4696-89c8-335febd420a4', 'Juntos', 'Que a nossa comunicação em casa seja um reflexo do Teu amor. Que nossas palavras construam vida hoje e sempre.', 3),
('5da133e3-9291-4486-a869-0e3639ae58d3', 'Pai', 'Senhor, ajuda-nos a buscar a sabedoria que Salomão descreveu. Dá-nos discernimento para identificar quando algo bom está se tornando um excesso em nossas vidas.', 1),
('5da133e3-9291-4486-a869-0e3639ae58d3', 'Filho', 'Deus, ensina-me a ter autocontrole nas minhas escolhas diárias. Quero aprender a parar antes que o meu comportamento me traga consequências ruins.', 2),
('5da133e3-9291-4486-a869-0e3639ae58d3', 'Juntos', 'Pai, guia nossos passos para que sejamos jovens e adultos equilibrados. Que a Tua medida seja sempre o nosso guia em tudo o que fizermos.', 3),
('5dbc2702-d305-419c-b4f7-05fc440da5a1', 'Individual', 'Senhor, reconheço que muitas vezes tento esconder minhas falhas atrás de argumentos e desculpas. Dá-me a coragem de Natã para enxergar meu próprio coração e a humildade de Davi para confessar que pequei contra Ti. Que minha vida seja marcada pela honestidade real e não pela aparência de justiça. Amém.', 1),
('5ddbdab0-6a0c-474d-8942-5fddf8213408', 'Pai', 'Papai do Céu, ensina-nos a ter olhos atentos para quem precisa de ajuda. Que nosso coração seja generoso como o do samaritano.', 1),
('5ddbdab0-6a0c-474d-8942-5fddf8213408', 'Filho', 'Jesus, ajuda-me a ser um bom amigo e a cuidar dos meus colegas com carinho. Quero amar os outros como o Senhor me ama.', 2),
('5ddbdab0-6a0c-474d-8942-5fddf8213408', 'Juntos', 'Obrigado por nos ensinar o caminho da bondade. Que possamos ser luz na vida de quem estiver ao nosso lado hoje.', 3),
('5e0b7647-1452-429e-a1a8-35c527d9d9a7', 'Pai', 'Senhor, ensina-nos a enxergar as bênçãos diárias que recebemos e a nunca esquecermos de Quem provém a vida. Que sejamos uma família que reconhece e valoriza cada gesto de bondade.', 1),
('5e0b7647-1452-429e-a1a8-35c527d9d9a7', 'Filho', 'Deus, ajuda-me a não ser como aqueles que recebem e esquecem. Que meu coração seja sensível para notar quem me ajuda e que eu sempre saiba agradecer.', 2),
('5e0b7647-1452-429e-a1a8-35c527d9d9a7', 'Juntos', 'Obrigado, Pai, por Tua misericórdia que nos alcança todos os dias. Que a gratidão seja o selo de nossas escolhas e o caminho para o nosso crescimento.', 3),
('5e37ee55-0b7d-4de9-8dc2-ef3102a9f923', 'Pai', 'Senhor, ajuda-nos a valorizar a firmeza de Daniel. Dá ao meu filho a coragem de ser fiel ao que é certo.', 1),
('5e37ee55-0b7d-4de9-8dc2-ef3102a9f923', 'Filho', 'Deus, ajuda-me a não ter medo de me posicionar quando o que pedem contradiz Tua vontade. Dá-me sabedoria para agir.', 2),
('5e37ee55-0b7d-4de9-8dc2-ef3102a9f923', 'Juntos', 'Pai, que nossas escolhas hoje construam um caráter aprovado. Que sejamos firmes em Ti, não importa a pressão.', 3),
('5e4bf57c-7f5e-4ea9-8ce6-35888670ecde', 'Pai', 'Senhor, ajuda-nos a cultivar um lar onde a verdade seja sempre bem-vinda. Que nossos filhos aprendam a valorizar a honestidade em cada pequena atitude.', 1),
('5e4bf57c-7f5e-4ea9-8ce6-35888670ecde', 'Filho', 'Papai do Céu, ajuda meu coração a ser corajoso e verdadeiro. Quero sempre falar o que é certo para te deixar muito feliz.', 2),
('5e4bf57c-7f5e-4ea9-8ce6-35888670ecde', 'Juntos', 'Obrigado, Deus, pela tua luz que nos guia. Queremos caminhar hoje e sempre com sinceridade e alegria no coração.', 3),
('5ee9e6fe-2064-4e20-bc02-e5da33cb5b92', 'Individual', 'Senhor, confesso que meu orgulho muitas vezes prefere o isolamento à correção de caminhos. Dá-me a humildade de Jacó para buscar quem ofendi e a sabedoria para restaurar o que destruí. Que a Tua paz guie meus passos e que minha vida seja um testemunho de reconciliação prática, removendo o peso de antigas contendas do meu coração. Amém.', 1),
('5f021eca-9c4b-441d-9c90-f2455038e1df', 'Pai', 'Pai do Céu, obrigado pelo presente de ensinar e cuidar dos meus filhos. Ajuda-me a ser um exemplo de amor e paciência todos os dias.', 1),
('5f021eca-9c4b-441d-9c90-f2455038e1df', 'Filho', 'Papai do Céu, obrigado por Jesus ter nos ensinado a obedecer. Ajuda-me a escutar e respeitar com alegria quem cuida de mim.', 2),
('5f021eca-9c4b-441d-9c90-f2455038e1df', 'Juntos', 'Senhor, que nossa casa seja um lugar de respeito e união. Que o amor de Jesus cresça em nós a cada novo amanhecer.', 3),
('5f26ca6f-2267-4caf-899d-7048fa3fcb6a', 'Individual', 'Senhor, reconheço que muitas vezes o medo de enfrentar minhas falhas me afasta da Tua luz. Dá-me a coragem de ser honesto sobre meus erros, sem buscar desculpas ou atalhos, confiando que a Tua misericórdia é maior que a minha culpa. Ensina-me a andar na verdade, restaurando a integridade do meu coração. Amém.', 1),
('5f29fbdc-7af1-45c9-bd70-1090fe445bc7', 'Pai', 'Papai do Céu, obrigado porque Tu estás sempre perto dos meus filhos, especialmente quando eles estão tristes. Ajuda-os a confiar no Teu cuidado em todos os momentos.', 1),
('5f29fbdc-7af1-45c9-bd70-1090fe445bc7', 'Filho', 'Querido Deus, quando eu ficar com medo ou triste, segura a minha mão. Ajuda-me a lembrar que o Senhor cuida de mim como cuidou do pequeno Davi.', 2),
('5f29fbdc-7af1-45c9-bd70-1090fe445bc7', 'Juntos', 'Obrigado, Deus, porque nunca estamos sozinhos. Tu és a nossa força e o nosso refúgio de amor todos os dias!', 3),
('5f8345cf-ef14-40cd-a53f-e9a7c6141ec1', 'Pai', 'Senhor, ajuda-nos a construir nossa casa sobre o fundamento da Tua Palavra. Que nossas palavras sirvam apenas para edificar o que é eterno.', 1),
('5f8345cf-ef14-40cd-a53f-e9a7c6141ec1', 'Filho', 'Pai, perdoa-me pelas vezes em que busquei apenas o meu reconhecimento. Ensina-me a usar minha voz para buscar a Tua vontade, e não a minha.', 2),
('5f8345cf-ef14-40cd-a53f-e9a7c6141ec1', 'Juntos', 'Que a nossa comunicação seja sempre temperada com verdade e sabedoria. Que sejamos unidos pelo Teu propósito, hoje e sempre.', 3),
('601ed101-ff4e-4fb4-a95c-90fbbd1e3325', 'Pai', 'Senhor, dá aos nossos filhos a sabedoria para escolherem amigos que temam ao Senhor. Que eles encontrem companhias que protejam o caráter deles como Jônatas protegeu Davi.', 1),
('601ed101-ff4e-4fb4-a95c-90fbbd1e3325', 'Filho', 'Pai do céu, ajuda-me a ser um amigo fiel e a valorizar pessoas que me aproximam de Ti. Que eu tenha coragem para escolher o caminho certo, mesmo que esteja sozinho.', 2),
('601ed101-ff4e-4fb4-a95c-90fbbd1e3325', 'Juntos', 'Deus, que nossa família seja um exemplo de lealdade e verdade. Ajuda-nos a discernir as influências ao nosso redor e a caminhar sempre em Tua luz.', 3),
('601f12ea-f45e-4911-8f26-c455697d2cfa', 'Individual', 'Senhor, concede-me a sabedoria para distinguir entre a provisão e o excesso. Ajuda-me a governar meus apetites e a encontrar contentamento na medida certa, para que eu não transforme tuas bênçãos em peso. Dá-me domínio próprio para parar quando necessário e viver com sobriedade diante da tua face. Amém.', 1),
('60478990-7b77-48f6-9c03-c0528a7b5816', 'Individual', 'Senhor, ajuda-me a edificar um coração que decide obedecer antes mesmo das tentações surgirem. Que a tua Palavra seja o limite para os meus desejos e a fonte da minha força, permitindo-me manter a integridade diante de qualquer mesa ou sistema deste mundo. Amém.', 1),
('6050b508-d47e-4909-8424-941c72148894', 'Individual', 'Senhor, ajuda-me a abandonar as justificativas que protegem meu orgulho. Dá-me a coragem de reconhecer onde errei e a humildade de retornar ao caminho da integridade, confiando não em minha justiça, mas na Tua misericórdia que restaura todas as coisas. Amém.', 1),
('60e328cc-acfa-4260-b574-8d2afa3cba04', 'Pai', 'Senhor, ajuda-me a ser um pai que acolhe o arrependimento dos meus filhos com compaixão. Que meu coração esteja sempre aberto para aqueles que decidem voltar ao caminho reto.', 1),
('60e328cc-acfa-4260-b574-8d2afa3cba04', 'Filho', 'Pai do Céu, dá-me a coragem de reconhecer meus erros imediatamente. Ajuda-me a escolher sempre a verdade, mesmo quando for difícil assumir minhas faltas.', 2),
('60e328cc-acfa-4260-b574-8d2afa3cba04', 'Juntos', 'Que a nossa casa seja um refúgio de honestidade e perdão. Ajuda-nos, Senhor, a perseverar juntos na Tua vontade todos os dias.', 3),
('61401a1e-3ea7-4b6f-93b7-dc5274099542', 'Pai', 'Senhor, ajuda-nos a confiar em Tua proteção mesmo quando as circunstâncias ao redor parecem confusas. Ensina-nos a manter nosso coração grato em todo o tempo.', 1),
('61401a1e-3ea7-4b6f-93b7-dc5274099542', 'Filho', 'Deus, eu quero aprender a Te louvar mesmo quando me sinto triste ou pressionado na escola. Ajuda-me a lembrar que o Senhor está comigo sempre.', 2),
('61401a1e-3ea7-4b6f-93b7-dc5274099542', 'Juntos', 'Pai, que o nosso louvor seja a nossa primeira resposta diante de qualquer desafio. Amém.', 3),
('614a1dee-465c-4e02-826a-d63d3d18a052', 'Pai', 'Senhor, dá aos nossos filhos a coragem necessária para admitirem suas falhas. Que eles encontrem em nossa casa um porto seguro para a verdade.', 1),
('614a1dee-465c-4e02-826a-d63d3d18a052', 'Filho', 'Pai do Céu, ajuda-me a não fugir das minhas responsabilidades. Dá-me forças para encarar meus erros e ser honesto com quem amo.', 2),
('614a1dee-465c-4e02-826a-d63d3d18a052', 'Juntos', 'Que a nossa família seja sempre marcada pelo perdão e pela humildade. Ensina-nos a caminhar sempre na direção da Tua luz.', 3),
('616d7a2c-1dc2-44c2-a4a6-ebd69949ef0a', 'Pai', 'Senhor, ensina-me a confiar em Ti mesmo quando as circunstâncias ao meu redor forem difíceis. Que a vida do meu filho reflita fidelidade em todos os lugares.', 1),
('616d7a2c-1dc2-44c2-a4a6-ebd69949ef0a', 'Filho', 'Deus, ajuda-me a ser corajoso para fazer o certo, mesmo quando ninguém estiver olhando. Que meu coração seja grato a Ti em todo o tempo.', 2),
('616d7a2c-1dc2-44c2-a4a6-ebd69949ef0a', 'Juntos', 'Pai, que o nosso louvor seja sincero e que nossas ações glorifiquem o Teu nome todos os dias. Amém.', 3),
('61ead4bd-f95e-47f2-82c4-62d1ec83fed1', 'Pai', 'Papai do Céu, obrigado porque o Senhor nos ensina a amar sempre. Ajuda-nos a ter um coração bondoso como o de José.', 1),
('61ead4bd-f95e-47f2-82c4-62d1ec83fed1', 'Filho', 'Jesus, tira toda a tristeza do meu coração quando alguém me faz algo ruim. Ensina-me a dar abraços e perdoar como Tu fazes comigo.', 2),
('61ead4bd-f95e-47f2-82c4-62d1ec83fed1', 'Juntos', 'Querido Deus, abençoa nossa família para sermos sempre unidos pelo amor. Que o nosso lar seja sempre um lugar de perdão.', 3),
('626235c0-e3f8-44a7-9e9b-b32c12b28870', 'Individual', 'Senhor, ajuda-me a abandonar a teimosia que mascara minhas falhas. Que eu tenha a honestidade do filho que retornou, reconhecendo meus erros diante de Ti sem artifícios ou justificativas, e a coragem de buscar a retidão necessária para viver de forma íntegra e fiel diante de Ti e dos homens.', 1),
('62fa9ddd-9da2-40cc-8d6b-e2e5fb15c356', 'Individual', 'Senhor, ajuda-me a cultivar a mesma firmeza de Daniel. Que minha vida de oração não seja ditada pela aprovação das pessoas ou pelo medo das circunstâncias, mas por uma devoção inabalável a Ti. Fortalece o meu autogoverno para que, diante de qualquer pressão, eu permaneça fiel aos Teus princípios e caminhe com integridade, sabendo que Tu és o meu verdadeiro Juiz.', 1),
('6333c65c-3e9d-40aa-833d-b8c627a19544', 'Pai', 'Senhor, ensina-nos a honrar nossos compromissos com fidelidade. Dá-nos um coração firme como o de Rute.', 1),
('6333c65c-3e9d-40aa-833d-b8c627a19544', 'Filho', 'Deus, ajuda-me a escolher o caminho da integridade nas minhas decisões escondidas. Que eu honre as pessoas que caminham comigo.', 2),
('6333c65c-3e9d-40aa-833d-b8c627a19544', 'Juntos', 'Pai, que nossa família seja um exemplo de lealdade e temor ao Teu nome. Fortalece nossa aliança uns com os outros.', 3),
('63594644-eea6-449c-a98e-ba773e54d684', 'Pai', 'Senhor, ajuda-nos a controlar nossa fala e a usar nossas palavras para semear vida em casa. Que nossos lábios sejam instrumentos de sabedoria e verdade.', 1),
('63594644-eea6-449c-a98e-ba773e54d684', 'Filho', 'Pai, ensina-me a pensar antes de responder e a escolher o silêncio quando a raiva surgir. Quero que meu falar reflita o Teu caráter.', 2),
('63594644-eea6-449c-a98e-ba773e54d684', 'Juntos', 'Deus, guiamos nossos diálogos pela Tua Palavra. Que nossa família seja conhecida por palavras que edificam e honram o Teu nome.', 3),
('63829d43-3452-4239-91e1-c744b3a1c352', 'Pai', 'Pai do céu, obrigado por nos ensinar a valorizar a simplicidade. Ajuda-me a guiar meu filho com o coração manso que Jesus nos pediu.', 1),
('63829d43-3452-4239-91e1-c744b3a1c352', 'Filho', 'Papai do céu, ajuda-me a ser obediente e a confiar sempre em ti. Ensina meu coração a ser humilde e bondoso com todos.', 2),
('63829d43-3452-4239-91e1-c744b3a1c352', 'Juntos', 'Senhor, faze-nos crescer em amor e união como tua família. Que sejamos sempre pequenos para que tu sejas grande em nós.', 3),
('63b7f709-bc3b-4c73-9464-e5a7bdd7239b', 'Individual', 'Senhor, perdoa-me por tantas vezes tentar exaltar meu próprio nome e proteger minha importância. Ensina-me a ter a mesma mente de Cristo, esvaziando-me do meu egoísmo e servindo aos que me cercam com fidelidade. Que a Tua glória, e não a minha, seja o alvo de todas as minhas ações e decisões neste dia. Amém.', 1),
('63f4f009-9fff-43da-b28b-546b0cab7f9f', 'Individual', 'Senhor, reconheço que muitas vezes minha generosidade é medida pela segurança do que sobra. Ajuda-me a enxergar meus recursos não como possessões a serem protegidas, mas como ferramentas para servir. Desata as amarras da minha avareza e ensina-me a confiar em Ti com total desprendimento. Que a minha vida seja uma entrega sincera, refletindo a confiança de quem sabe que o Senhor é o meu verdadeiro sustento. Amém.', 1),
('6426a436-10ce-4f94-8a0b-178786b7cc75', 'Pai', 'Senhor, dá aos meus filhos sabedoria para identificar as distrações e firmeza para manter o foco no que é certo.', 1),
('6426a436-10ce-4f94-8a0b-178786b7cc75', 'Filho', 'Pai, ajuda-me a não ceder às pressões do caminho e a terminar bem as tarefas que o Senhor me confiou.', 2),
('6426a436-10ce-4f94-8a0b-178786b7cc75', 'Juntos', 'Que nossa família seja reconhecida pela fidelidade e pela disposição de construir algo bom diante de Ti. Amém.', 3),
('65227870-83e6-4e39-a438-40b55b235c39', 'Pai', 'Senhor, ajuda-me a guiar meus filhos para que olhem sempre para o que é verdadeiro. Que eles possam discernir Tua vontade em meio a tantas distrações.', 1),
('65227870-83e6-4e39-a438-40b55b235c39', 'Filho', 'Pai do céu, peço que guardes os meus olhos de desejarem o que não agrada a Ti. Dá-me clareza para escolher o caminho certo hoje.', 2),
('65227870-83e6-4e39-a438-40b55b235c39', 'Juntos', 'Deus, que a Tua luz ilumine nossas decisões em casa e na escola. Ajuda-nos a sermos fiéis ao Teu ensino em todos os momentos.', 3),
('6533a949-3e2e-43d4-8f09-a57e1c333324', 'Pai', 'Senhor, ajuda-nos a criar um ambiente de silêncio e paz em nossa casa. Que possamos sempre estar atentos à Tua voz.', 1),
('6533a949-3e2e-43d4-8f09-a57e1c333324', 'Filho', 'Papai do Céu, ensina meu coração a parar de brincar para te ouvir. Quero ser como Samuel e te obedecer.', 2),
('6533a949-3e2e-43d4-8f09-a57e1c333324', 'Juntos', 'Querido Deus, nós queremos ser Teus servos. Fala conosco, pois estamos prontos para ouvir e seguir o Teu caminho.', 3),
('65e126f1-d409-4393-b213-d9f58e56dff3', 'Pai', 'Papai do céu, ensina meus filhos a terem um coração generoso como o da viúva. Que eles saibam que tudo o que temos vem do Teu cuidado.', 1),
('65e126f1-d409-4393-b213-d9f58e56dff3', 'Filho', 'Jesus, ajuda-me a repartir meus brinquedos com alegria. Que eu possa cuidar dos outros com o mesmo carinho que Tu cuidas de mim.', 2),
('65e126f1-d409-4393-b213-d9f58e56dff3', 'Juntos', 'Obrigado, Deus, pelo Teu amor que nunca acaba. Queremos aprender a oferecer sempre o nosso melhor para Ti e para os nossos amigos.', 3),
('6647acd3-b4fc-40a1-b28b-cd17e588c13f', 'Pai', 'Senhor, ajuda-nos a sermos pais que acolhem, prontos para perdoar como Tu perdoas. Que nossa casa seja sempre um porto seguro para a verdade.', 1),
('6647acd3-b4fc-40a1-b28b-cd17e588c13f', 'Filho', 'Deus, dá-me coragem para admitir meus erros aos meus amigos. Que eu saiba pedir desculpas com sinceridade e sem desculpas.', 2),
('6647acd3-b4fc-40a1-b28b-cd17e588c13f', 'Juntos', 'Pai, ensina-nos o valor da humildade e da reconciliação. Que nosso amor uns pelos outros seja maior que qualquer orgulho.', 3),
('6673aa0d-1f25-4c86-925a-c4ab76cba051', 'Pai', 'Senhor, dá aos nossos filhos a coragem de Daniel para honrarem Teus caminhos. Ajuda-os a serem firmes em suas convicções.', 1),
('6673aa0d-1f25-4c86-925a-c4ab76cba051', 'Filho', 'Deus, ajuda-me a escolher o que é certo mesmo quando todos fazem o contrário. Dá-me sabedoria para decidir o que me agrada.', 2),
('6673aa0d-1f25-4c86-925a-c4ab76cba051', 'Juntos', 'Pedimos que o Senhor nos guie e nos fortaleça em cada escolha do dia. Que nossa vida sempre reflita a Tua vontade.', 3),
('667b7f1f-5c1a-4dc8-961d-c9fd167adda0', 'Pai', 'Papai do Céu, obrigado pelos presentes doces que o Senhor nos dá todos os dias. Ajuda-nos a desfrutar de tudo com gratidão e sem exageros.', 1),
('667b7f1f-5c1a-4dc8-961d-c9fd167adda0', 'Filho', 'Jesus, ensina o meu coração a ser obediente e a saber a hora de parar. Quero aprender a cuidar das coisas que o Senhor me deu.', 2),
('667b7f1f-5c1a-4dc8-961d-c9fd167adda0', 'Juntos', 'Que a nossa família saiba viver com equilíbrio e alegria. Amém!', 3),
('66d6214a-d31f-4769-938d-4e59a3db09c9', 'Individual', 'Senhor, reconheço que muitas vezes tentei justificar meus caminhos errados. Ajuda-me a ter a coragem de olhar para a minha vida com honestidade, sem disfarces. Que a Tua compaixão me conduza ao arrependimento genuíno e que eu saiba buscar a reconciliação com humildade e verdade. Amém.', 1),
('66f3e84e-5289-4b32-9398-29d018183f75', 'Pai', 'Senhor, ensina-nos a enxergar as necessidades do próximo com Teus olhos. Que nossa família nunca seja indiferente ao sofrimento alheio.', 1),
('66f3e84e-5289-4b32-9398-29d018183f75', 'Filho', 'Ajuda-me a ter a coragem de parar, mesmo quando estiver com pressa. Que minhas ações demonstrem bondade em vez de apenas palavras.', 2),
('66f3e84e-5289-4b32-9398-29d018183f75', 'Juntos', 'Pai, faz de nós instrumentos de Tua compaixão no mundo. Que nosso caráter reflita o amor sacrificial que Jesus nos ensinou.', 3),
('671c88b6-8011-4e4e-816f-b2b0adc958de', 'Pai', 'Senhor, ajuda-nos a educar nossos filhos para que a Tua presença seja o limite de suas decisões. Que o temor a Ti seja maior do que qualquer impulso passageiro.', 1),
('671c88b6-8011-4e4e-816f-b2b0adc958de', 'Filho', 'Deus, dá-me coragem para fugir daquilo que Te ofende. Que eu valorize mais a Tua aprovação do que a aceitação de qualquer pessoa.', 2),
('671c88b6-8011-4e4e-816f-b2b0adc958de', 'Juntos', 'Que a nossa casa seja um lugar de verdade e integridade. Ajuda-nos a sermos fiéis nos detalhes, honrando o Teu nome em cada escolha diária.', 3),
('676f7f09-ad31-44c7-93d7-d90c9bfe237a', 'Pai', 'Senhor, ajuda-nos a criar filhos que não temem o conflito quando a verdade precisa ser dita. Dá-nos sabedoria para sermos modelos de integridade.', 1),
('676f7f09-ad31-44c7-93d7-d90c9bfe237a', 'Filho', 'Pai do Céu, dá-me coragem para não fugir das tensões. Ajuda-me a ser um instrumento de paz onde quer que eu vá.', 2),
('676f7f09-ad31-44c7-93d7-d90c9bfe237a', 'Juntos', 'Deus, que o nosso lar seja um lugar de verdade e reconciliação. Que sejamos conhecidos como Teus filhos pela paz que semeamos.', 3),
('680192c2-d919-44ba-9dd7-46810bd607ab', 'Pai', 'Pai do céu, obrigado porque o Teu amor é maior que qualquer erro nosso. Ajuda-nos a sempre correr de volta para Ti quando falharmos.', 1),
('680192c2-d919-44ba-9dd7-46810bd607ab', 'Filho', 'Querido Deus, me ajude a ter um coração manso para pedir desculpas. Quero ser um filho obediente e muito feliz ao Teu lado.', 2),
('680192c2-d919-44ba-9dd7-46810bd607ab', 'Juntos', 'Obrigado, Deus, pelo Teu perdão que renova nossa família hoje. Queremos viver sempre com alegria na Tua casa.', 3),
('6814d2f9-86a4-4854-a186-dee17f2e414c', 'Pai', 'Papai do céu, ensina nossos filhos a terem um coração bondoso. Que eles sempre vejam quem precisa de um amigo.', 1),
('6814d2f9-86a4-4854-a186-dee17f2e414c', 'Filho', 'Jesus, ajuda-me a ser um bom ajudante hoje. Que eu tenha olhos de amor para quem estiver perto de mim.', 2),
('6814d2f9-86a4-4854-a186-dee17f2e414c', 'Juntos', 'Obrigado, Deus, pelo Teu amor que nos ensina a amar. Queremos ser como o samaritano todos os dias!', 3),
('681d0470-3d12-4f72-9142-c07ea1da641d', 'Pai', 'Senhor, ajuda-nos a cultivar amizades que honrem o Teu nome. Que possamos ser amigos leais e firmes em todo o tempo.', 1),
('681d0470-3d12-4f72-9142-c07ea1da641d', 'Filho', 'Pai, peço que me dês sabedoria para escolher bem aqueles que andam ao meu lado. Que minhas amizades reflitam os Teus valores.', 2),
('681d0470-3d12-4f72-9142-c07ea1da641d', 'Juntos', 'Obrigado por nos unires em família. Ajuda-nos a sermos um apoio um para o outro em toda e qualquer circunstância.', 3),
('6837ec18-5d84-43a2-af54-5a16f50fa676', 'Individual', 'Senhor, reconheço que muitas vezes tentei esconder minhas falhas atrás de desculpas. Dá-me a coragem de ser honesto diante de Ti e dos homens, sem medo de perder o que não me pertence. Que meu arrependimento seja real e produza um coração íntegro, focado inteiramente na Tua vontade. Amém.', 1),
('686bee59-69fb-4409-bbc6-3fa09957b20a', 'Pai', 'Senhor, ajuda-me a ensinar o meu filho a escolher sempre o caminho da tua sabedoria. Que sejamos uma família que ouve a tua voz acima de qualquer outra.', 1),
('686bee59-69fb-4409-bbc6-3fa09957b20a', 'Filho', 'Papai do Céu, por favor, me dê coragem para dizer não quando alguém quiser que eu faça algo que não te agrada. Quero ser um amigo que escolhe o bem.', 2),
('686bee59-69fb-4409-bbc6-3fa09957b20a', 'Juntos', 'Obrigado, Deus, por nos proteger e por nos guiar pelo caminho seguro. Ajuda-nos a andar sempre com quem ama a Ti.', 3),
('687659ad-e92f-48cc-a9c9-713c31b06dc6', 'Pai', 'Senhor, ajuda-me a ser um exemplo de autocontrole para meu filho. Que possamos edificar uma casa fundamentada na Tua Palavra.', 1),
('687659ad-e92f-48cc-a9c9-713c31b06dc6', 'Filho', 'Deus, dá-me sabedoria para governar meus impulsos. Ajuda-me a escolher a retidão, mesmo quando ninguém estiver me observando.', 2),
('687659ad-e92f-48cc-a9c9-713c31b06dc6', 'Juntos', 'Pai, fortaleça nossa união e nosso caráter. Que sejamos homens e mulheres íntegros que constroem muros sólidos para Tua glória.', 3),
('68840473-c391-4f8d-a3e6-c71e96427e7e', 'Pai', 'Papai do céu, ajuda-nos a ensinar nossos filhos a valorizarem Tua vontade acima de tudo. Dá-nos sabedoria para sermos exemplos de obediência em nossa casa.', 1),
('68840473-c391-4f8d-a3e6-c71e96427e7e', 'Filho', 'Querido Deus, ajuda-me a ser corajoso como Daniel. Quando eu tiver vontade de fazer o errado, lembra-me de escolher o Teu caminho.', 2),
('68840473-c391-4f8d-a3e6-c71e96427e7e', 'Juntos', 'Obrigado, Senhor, porque Tu cuidas de nós. Queremos Te amar e Te obedecer todos os dias de nossas vidas!', 3),
('68a9a487-ac17-4d60-a4a6-7f8d34eb0588', 'Pai', 'Senhor, ensina nossos filhos a buscarem a Tua paz que excede todo o entendimento. Que eles saibam onde encontrar refúgio nos dias difíceis.', 1),
('68a9a487-ac17-4d60-a4a6-7f8d34eb0588', 'Filho', 'Jesus, ajuda-me a não deixar meu coração ficar perturbado com as preocupações da escola. Dá-me Tua serenidade hoje.', 2),
('68a9a487-ac17-4d60-a4a6-7f8d34eb0588', 'Juntos', 'Obrigado, Deus, porque a Tua paz é real e habita em nós. Que ela seja a nossa força em todos os momentos.', 3),
('68c6e9b3-63b9-4807-8b22-7d15ca2269e3', 'Individual', 'Senhor, não permitas que o temor ou a hesitação me desviem da Tua vontade. Concede-me a clareza para observar a Tua Palavra e a força para agir conforme o Teu comando, confiando que a Tua presença é a minha real segurança. Que minha vida seja pautada pela obediência, moldando meu caráter para ser fiel em cada desafio. Amém.', 1),
('690f0818-6426-42a0-b7dd-02f18192fff6', 'Pai', 'Querido Deus, ajuda o meu filho a ter um coração firme e obediente. Que ele sempre escolha seguir os Teus mandamentos com alegria.', 1),
('690f0818-6426-42a0-b7dd-02f18192fff6', 'Filho', 'Papai do céu, ensina-me a ser corajoso como Daniel. Ajuda-me a fazer o que é certo, mesmo quando for difícil.', 2),
('690f0818-6426-42a0-b7dd-02f18192fff6', 'Juntos', 'Obrigado, Senhor, por nos dar a Tua Palavra como guia. Queremos sempre Te obedecer e crescer em Tua presença!', 3),
('6a074623-3b00-4df7-8266-0064e9f0d5ed', 'Pai', 'Senhor, ajuda-nos a ter um coração disposto a pedir perdão. Que possamos sempre acolher um ao outro com amor e sem julgamentos.', 1),
('6a074623-3b00-4df7-8266-0064e9f0d5ed', 'Filho', 'Deus, dá-me coragem para admitir quando erro, em vez de esconder minhas falhas. Ensina-me a ser leal às pessoas que amo.', 2),
('6a074623-3b00-4df7-8266-0064e9f0d5ed', 'Juntos', 'Pai, obrigado porque o Teu perdão nos renova todos os dias. Que a nossa família seja sempre um lugar de honestidade e restauração.', 3),
('6a07741f-6307-4b19-ad64-bcd4f431e3da', 'Individual', 'Senhor, dá-me discernimento para avaliar as influências que permito em minha vida. Que eu tenha a coragem de me cercar daqueles que buscam a Tua sabedoria, preservando meu coração de desvios e mantendo minha integridade firme diante de Ti. Amém.', 1),
('6a300176-ec49-493b-bddd-d58ebd5b4978', 'Pai', 'Senhor, ensina-nos a confiar em Ti mesmo nas situações mais difíceis e dolorosas. Que nossa fé não dependa das circunstâncias, mas da Tua presença.', 1),
('6a300176-ec49-493b-bddd-d58ebd5b4978', 'Filho', 'Deus, ajuda-me a ser verdadeiro e honesto na escola e com meus amigos, mesmo quando ninguém estiver me observando. Que o meu coração seja sempre Teu.', 2),
('6a300176-ec49-493b-bddd-d58ebd5b4978', 'Juntos', 'Pai, que o nosso louvor seja a nossa resposta diante de qualquer desafio. Que a nossa vida glorifique o Teu nome em todo tempo.', 3),
('6a30c8bc-cbdc-4d8e-99d8-1dba1c972330', 'Pai', 'Senhor, ajuda-nos a ser pessoas de palavra e leais, como Davi foi diante de Saul. Que nossa integridade nunca dependa de quem está nos olhando.', 1),
('6a30c8bc-cbdc-4d8e-99d8-1dba1c972330', 'Filho', 'Deus, dá-me coragem para escolher o caminho certo na escola e com meus amigos. Que eu seja sempre um amigo fiel, mesmo quando ninguém vir minhas escolhas.', 2),
('6a30c8bc-cbdc-4d8e-99d8-1dba1c972330', 'Juntos', 'Que nossa família seja marcada pela fidelidade e pela honra a Ti em todos os momentos. Amém.', 3),
('6a7560e5-61ce-49fd-9e83-71d116ec9106', 'Individual', 'Senhor, reconheço que meu esforço para controlar o futuro é um sinal da minha falta de confiança. Perdoa-me pelas horas desperdiçadas na angústia e ajuda-me a abraçar a tarefa de hoje com fidelidade, entregando a Ti tudo aquilo que foge ao meu alcance. Que o meu descanso seja a prova da minha fé.', 1),
('6b29661f-cff2-4b7f-94a6-3e4420167439', 'Pai', 'Senhor, ajuda-nos a ser pais que acolhem com amor os erros dos nossos filhos. Que sejamos um porto seguro para a verdade.', 1),
('6b29661f-cff2-4b7f-94a6-3e4420167439', 'Filho', 'Deus, dá-me coragem para não esconder minhas falhas. Que eu tenha a humildade de pedir perdão sempre que eu errar.', 2),
('6b29661f-cff2-4b7f-94a6-3e4420167439', 'Juntos', 'Pai, obrigado por nos ensinar que a integridade traz paz ao coração. Que nossa casa seja um lugar de verdade.', 3),
('6b5c5aaf-832f-403e-b406-293f1dc5b5c8', 'Pai', 'Senhor, ajuda-nos a confiar no Teu amor, mesmo nos dias mais difíceis. Ensina-nos a adorar o Teu nome em todo tempo.', 1),
('6b5c5aaf-832f-403e-b406-293f1dc5b5c8', 'Filho', 'Papai do céu, eu fico triste quando perco minhas coisas, mas sei que Tu cuidas de mim. Obrigado por estar sempre perto.', 2),
('6b5c5aaf-832f-403e-b406-293f1dc5b5c8', 'Juntos', 'Obrigado, Deus, porque o Senhor é nosso melhor amigo. Queremos Te amar de todo o coração, hoje e sempre!', 3),
('6b819475-5c1f-478c-a5f4-b72f8cd80d44', 'Individual', 'Senhor, meu Deus, confesso que por vezes deixei minha obediência ser ditada pela facilidade, negligenciando a honra que Te é devida. Peço que purifiques meu coração e dês-me a coragem necessária para priorizar Tua vontade acima de qualquer relação ou desejo pessoal. Que minha vida seja, em cada detalhe oculto, um testemunho de reverência e temor ao Teu nome. Que o meu caminhar reflita a integridade de quem Te reconhece como o único Senhor de todas as coisas. Amém.', 1),
('6bd73bea-9c1b-4257-9167-705df9258e42', 'Pai', 'Senhor, ajuda-nos a colocar o orgulho de lado e a olhar para as necessidades de quem convive conosco. Ensina-nos a servir uns aos outros com alegria.', 1),
('6bd73bea-9c1b-4257-9167-705df9258e42', 'Filho', 'Pai do Céu, tira do meu coração o desejo de ser sempre o centro das atenções. Que minhas mãos estejam prontas para ajudar meus amigos e minha família.', 2),
('6bd73bea-9c1b-4257-9167-705df9258e42', 'Juntos', 'Que o exemplo de Jesus seja o nosso guia diário em casa e na escola. Amém.', 3),
('6be30fd2-1ac1-46f8-8f80-4161b7c5a825', 'Pai', 'Senhor, ensina-me a ser um exemplo de fidelidade para meus filhos. Que meu caráter seja constante, independentemente das circunstâncias.', 1),
('6be30fd2-1ac1-46f8-8f80-4161b7c5a825', 'Filho', 'Deus, ajuda-me a manter minhas promessas e a ser leal aos meus valores. Que eu honre a Ti em cada escolha secreta.', 2),
('6be30fd2-1ac1-46f8-8f80-4161b7c5a825', 'Juntos', 'Pai, que nossa família caminhe sempre com verdade e honra. Que nossa lealdade a Ti seja o alicerce de nossas vidas.', 3),
('6c3a41b0-3e35-4ce1-9596-8378cec4bc75', 'Individual', 'Senhor, peço sabedoria para examinar as influências que permito em minha vida. Dá-me discernimento para honrar amizades que refletem o Teu temor e coragem para me afastar de caminhos que afastam o meu coração da Tua verdade. Que minha vida seja guiada por conselhos retos e que eu seja, também, um instrumento de sabedoria para aqueles que me cercam. Amém.', 1),
('6c8897bd-cc5e-472d-b78b-5a3c829c6ce7', 'Individual', 'Senhor, reconheço que meu medo muitas vezes me faz olhar mais para as circunstâncias do que para a Tua ordem. Concede-me a clareza de Tua Palavra e a firmeza necessária para avançar com integridade. Não permitas que a hesitação limite o serviço que devo prestar a Ti. Que Tua presença seja meu consolo e minha força diante de cada desafio deste dia. Amém.', 1),
('6cc9e6c9-8e6e-4d56-90b2-8949870bd34a', 'Individual', 'Senhor, ajuda-me a governar o meu olhar e a manter a firmeza nos passos. Que a minha atenção esteja sempre voltada para o que é justo e reto diante de Ti, livrando-me dos desvios que enfraquecem o meu caráter. Que o foco da minha vida seja a Tua verdade, para que, em cada passo, eu construa um caminho de fidelidade e obediência. Amém.', 1),
('6d124e79-1d53-4ce2-91e0-d506bed03706', 'Individual', 'Senhor, ajuda-me a manter o coração inabalável diante das exigências deste mundo. Que a Tua vontade seja, em todas as horas, o padrão supremo das minhas decisões, fortalecendo meu caráter para permanecer fiel mesmo quando o custo parece alto. Amém.', 1),
('6d29b6b2-d8ee-4fd1-89b0-eda0b14b30ff', 'Pai', 'Senhor, ajuda-nos a ter a coragem de Davi. Que a nossa força seja sempre usada para proteger e não para ferir.', 1),
('6d29b6b2-d8ee-4fd1-89b0-eda0b14b30ff', 'Filho', 'Deus, dá-me um coração bondoso nas horas de raiva. Ensina-me a escolher o bem mesmo quando for difícil.', 2),
('6d29b6b2-d8ee-4fd1-89b0-eda0b14b30ff', 'Juntos', 'Pai, que nossas atitudes mostrem que pertencemos a Ti. Amém.', 3),
('6da3c037-5ffb-4992-a9e7-ee1950f2c497', 'Pai', 'Papai do Céu, obrigado por curar aqueles homens e por cuidar de nós todos os dias. Ajuda-nos a ter sempre um coração que sabe agradecer.', 1),
('6da3c037-5ffb-4992-a9e7-ee1950f2c497', 'Filho', 'Obrigado, Jesus, pelas coisas boas que recebo. Eu quero ser como aquele homem que voltou para te dar um abraço de gratidão.', 2),
('6da3c037-5ffb-4992-a9e7-ee1950f2c497', 'Juntos', 'Obrigado, Deus, por estares sempre perto de nossa família. Que nosso coração seja sempre alegre e cheio de gratidão ao Senhor.', 3),
('6dac9c73-cc0d-4d16-9363-d11e4913b580', 'Pai', 'Senhor, ajuda-me a ser um exemplo de firmeza e temor a Ti para meus filhos. Que meu caminhar diário reflita convicções inabaláveis em Tua Palavra.', 1),
('6dac9c73-cc0d-4d16-9363-d11e4913b580', 'Filho', 'Pai celestial, dá-me coragem para dizer não ao que desagrada o Senhor. Fortalece o meu coração para permanecer fiel mesmo quando todos decidirem seguir o caminho errado.', 2),
('6dac9c73-cc0d-4d16-9363-d11e4913b580', 'Juntos', 'Deus, que nossa família seja conhecida por adorar apenas a Ti em todas as circunstâncias. Que nossas escolhas, privadas e públicas, honrem sempre o Teu nome.', 3),
('6dadf9ec-de2a-46de-956a-a6b233aa00f1', 'Pai', 'Papai do Céu, obrigado pelo exemplo de amizade entre Davi e Jônatas. Ensina nossos filhos a serem amigos bondosos e fiéis.', 1),
('6dadf9ec-de2a-46de-956a-a6b233aa00f1', 'Filho', 'Jesus, ajuda-me a repartir minhas coisas com meus amigos. Quero ser um amigo que cuida e faz o bem.', 2),
('6dadf9ec-de2a-46de-956a-a6b233aa00f1', 'Juntos', 'Obrigado por nos ensinar a amar como o Senhor nos ama. Que nossa amizade seja sempre cheia de alegria e bondade.', 3),
('6db21c8a-2194-4bf8-a2ee-53cc06e45669', 'Pai', 'Senhor, ensina-nos a enxergar as necessidades alheias com os Teus olhos. Que nossa casa seja um refúgio de atitudes generosas e corajosas.', 1),
('6db21c8a-2194-4bf8-a2ee-53cc06e45669', 'Filho', 'Pai, ajuda-me a não ser indiferente às dores dos outros. Que eu tenha disposição para agir, mesmo quando o conforto me convida a parar.', 2),
('6db21c8a-2194-4bf8-a2ee-53cc06e45669', 'Juntos', 'Deus, transforma nosso coração para sermos próximos daqueles que sofrem. Que nossa família viva a Tua compaixão em cada escolha diária.', 3),
('6de2257a-a03c-4278-90be-55bee609b89b', 'Pai', 'Papai do céu, ajuda o meu filho a ter um coração valente. Que ele nunca tenha medo de escolher o Teu caminho.', 1),
('6de2257a-a03c-4278-90be-55bee609b89b', 'Filho', 'Querido Deus, ajuda-me a ser obediente como Daniel. Dá-me forças para fazer sempre o que Te deixa feliz.', 2),
('6de2257a-a03c-4278-90be-55bee609b89b', 'Juntos', 'Senhor, somos Tua família e queremos Te servir juntos. Que nossa casa seja um lugar de obediência e amor.', 3),
('6df995de-d23a-41e8-bb38-6374c72156c3', 'Pai', 'Senhor, ajuda-nos a governar a nossa língua e a ser guardiões da confiança que nossos amigos depositam em nós.', 1),
('6df995de-d23a-41e8-bb38-6374c72156c3', 'Filho', 'Deus, dá-me coragem para silenciar quando algo for fofoca e sabedoria para honrar quem confia em mim.', 2),
('6df995de-d23a-41e8-bb38-6374c72156c3', 'Juntos', 'Que a nossa família seja conhecida por palavras que edificam e protegem. Amém.', 3),
('6eaad80c-2d59-422e-bc91-c9448b4d8573', 'Pai', 'Senhor, ajuda-nos a valorizar a integridade acima de qualquer ganho passageiro. Que eu seja um exemplo de lealdade para meu filho.', 1),
('6eaad80c-2d59-422e-bc91-c9448b4d8573', 'Filho', 'Pai Celestial, ensina-me a ser um amigo fiel e a cumprir minhas promessas, mesmo quando ninguém estiver me observando.', 2),
('6eaad80c-2d59-422e-bc91-c9448b4d8573', 'Juntos', 'Deus, fortaleça nossa aliança familiar. Que nossas escolhas sejam sempre guiadas pela Tua verdade e pelo Teu amor.', 3),
('6ecf9f79-e375-4cdf-8f2d-0da34b88eb15', 'Pai', 'Senhor, ajuda-nos a ter olhos atentos para ver o Teu agir em cada detalhe de nossa família. Que possamos ser gratos por cada cuidado recebido.', 1),
('6ecf9f79-e375-4cdf-8f2d-0da34b88eb15', 'Filho', 'Deus, perdoa-me quando recebo as coisas como se fossem obrigação. Ensina-me a valorizar quem me ajuda todos os dias.', 2),
('6ecf9f79-e375-4cdf-8f2d-0da34b88eb15', 'Juntos', 'Pai, que nossa casa seja um lugar de gratidão e reconhecimento. Amém.', 3),
('6ef6f6e8-b71f-4bfd-8de9-09725e1ebf36', 'Pai', 'Senhor, dá a este meu filho a coragem de ser honesto diante dos seus erros. Que ele saiba que sempre terá um lugar de amor ao voltar para casa.', 1),
('6ef6f6e8-b71f-4bfd-8de9-09725e1ebf36', 'Filho', 'Deus, ajuda-me a não esconder meus erros atrás de desculpas. Dá-me força para pedir perdão e ser sincero em todas as minhas atitudes.', 2),
('6ef6f6e8-b71f-4bfd-8de9-09725e1ebf36', 'Juntos', 'Pai, obrigado porque Teu amor é maior que nossas falhas. Ensina-nos a viver com respeito, verdade e sempre prontos para o perdão.', 3),
('6f5b5b65-b540-4fdf-9913-72ca34ab6702', 'Pai', 'Senhor, ajuda-nos a valorizar a verdade acima de qualquer vantagem imediata. Que nossa casa seja um lugar de homens e mulheres íntegros.', 1),
('6f5b5b65-b540-4fdf-9913-72ca34ab6702', 'Filho', 'Deus, dá-me coragem para fugir do erro como José fez. Ajuda-me a honrar Teu nome, mesmo quando ninguém estiver vendo.', 2),
('6f5b5b65-b540-4fdf-9913-72ca34ab6702', 'Juntos', 'Que nossa família caminhe na luz da Tua Palavra. Mantém nossos corações puros e leais ao Senhor todos os dias.', 3),
('6f5d93df-c548-4767-8827-7f0588ad1ce3', 'Pai', 'Senhor, ensina-nos a humildade de Jacó e a generosidade de Esaú. Que nossos corações sejam sempre abertos ao perdão.', 1),
('6f5d93df-c548-4767-8827-7f0588ad1ce3', 'Filho', 'Ajuda-me a deixar de lado o orgulho nas minhas amizades. Quero ser alguém que constrói a paz.', 2),
('6f5d93df-c548-4767-8827-7f0588ad1ce3', 'Juntos', 'Deus, ajuda nossa família a ser sempre um lugar de reconciliação. Que o teu amor nos una a cada dia.', 3),
('6f8dd4a5-2e2c-46a5-a9a5-11a68f09b071', 'Pai', 'Papai do Céu, obrigado por perdoar todas as nossas falhas com tanto amor. Ajuda-nos a ter um coração bondoso para também perdoar quem nos entristece.', 1),
('6f8dd4a5-2e2c-46a5-a9a5-11a68f09b071', 'Filho', 'Jesus, ensina-me a não guardar mágoas dentro de mim. Quero que meu coração seja leve e sempre cheio da tua alegria.', 2),
('6f8dd4a5-2e2c-46a5-a9a5-11a68f09b071', 'Juntos', 'Senhor, ajuda a nossa família a viver em paz e a perdoar sempre. Amém!', 3),
('6fd2b101-84bf-4d64-b3d6-a415685e2179', 'Individual', 'Senhor, ajuda-me a manter a firmeza e o autogoverno quando as tribulações me cercarem. Que eu não seja moldado pelo caos ao meu redor, mas que meu caráter permaneça inabalável pela Tua fidelidade. Ensina-me a ser como o apóstolo: pressionado, mas não esmagado; caído, mas não destruído. Que a minha vida honre a Tua soberania em cada decisão que eu tomar hoje. Amém.', 1),
('7055993a-d4cf-4c59-87e5-6626875c631a', 'Individual', 'Senhor, reconheço que muitas vezes me perdi em meus próprios caminhos e decisões equivocadas. Concede-me a coragem de abandonar as justificativas e o orgulho, para que eu possa sempre retornar aos Teus braços com sinceridade. Que minha vida demonstre um arrependimento genuíno, traduzido em ações retas e obediência fiel. Amém.', 1),
('7073c018-c4b4-443a-8527-9300a4923ae5', 'Pai', 'Senhor, ensina-nos a honrar nossos compromissos. Que nossas famílias sejam um testemunho de fidelidade.', 1),
('7073c018-c4b4-443a-8527-9300a4923ae5', 'Filho', 'Deus, ajuda-me a ser um amigo leal, mesmo quando for difícil. Dá-me coragem para escolher o certo.', 2),
('7073c018-c4b4-443a-8527-9300a4923ae5', 'Juntos', 'Que a nossa casa seja um lugar de palavra firme. Que sejamos leais como Rute foi a Noemi.', 3),
('71743437-7040-411a-bf50-0274c8a7793d', 'Individual', 'Senhor, concede-me a clareza de Neemias para identificar as armadilhas que tentam desviar meu foco. Que eu não confunda urgências passageiras com o meu propósito maior. Fortalece minha vontade para permanecer firme no trabalho que me deste, sem ceder às pressões ou ao desejo de desistir quando o esforço se torna exigente. Que a minha integridade seja mantida através da constância e que, ao final, eu possa ver a tua obra concluída. Amém.', 1),
('7236669e-a491-4fd5-a05c-38af8c772ec0', 'Pai', 'Senhor, ensina-me a ser um exemplo de serviço para meu filho. Que possamos aprender juntos a humildade de Cristo.', 1),
('7236669e-a491-4fd5-a05c-38af8c772ec0', 'Filho', 'Deus, ajuda-me a não buscar sempre o primeiro lugar. Dá-me um coração disposto a ajudar meus amigos e família.', 2),
('7236669e-a491-4fd5-a05c-38af8c772ec0', 'Juntos', 'Pai, que a nossa casa seja um lugar onde o orgulho não tem vez. Que sejamos servos uns dos outros.', 3),
('72630474-0936-4137-98bd-5b1345e283a6', 'Pai', 'Senhor, ajuda-nos a sermos como Daniel, mantendo nossa fidelidade mesmo sob pressão. Que nosso caráter seja aprovado por Ti em todos os momentos.', 1),
('72630474-0936-4137-98bd-5b1345e283a6', 'Filho', 'Pai do céu, peço forças para escolher o caminho certo, mesmo quando ninguém estiver olhando. Que minha vida brilhe para Ti em cada pequena decisão.', 2),
('72630474-0936-4137-98bd-5b1345e283a6', 'Juntos', 'Deus, pedimos que o Teu temor seja a base da nossa casa. Que possamos ser fiéis ao Senhor acima de qualquer decreto ou opinião humana.', 3),
('728682f8-44b6-46a7-adc8-d427530dbb7b', 'Pai', 'Senhor, ajuda-nos a usar nossas vozes para espalhar a tua paz em nossa casa. Que a nossa família seja um lugar de palavras gentis.', 1),
('728682f8-44b6-46a7-adc8-d427530dbb7b', 'Filho', 'Papai do Céu, ensina o meu coração a ser manso como o Teu. Ajuda-me a escolher palavras boas mesmo quando eu estiver bravo.', 2),
('728682f8-44b6-46a7-adc8-d427530dbb7b', 'Juntos', 'Obrigado, Deus, pelo presente da fala. Que cada palavra que dissermos hoje seja como um doce carinho para quem nos ouve.', 3),
('72fe5f41-3d85-4421-ae61-1bdc63447dd5', 'Pai', 'Senhor, ajuda-nos a ensinar aos nossos filhos que a Tua aprovação vale mais do que a de qualquer pessoa. Dá-nos sabedoria para sermos firmes na Tua verdade.', 1),
('72fe5f41-3d85-4421-ae61-1bdc63447dd5', 'Filho', 'Deus, dá-me coragem para dizer não quando o que pedem de mim não agrada a Ti. Que eu saiba escolher o caminho certo, mesmo que seja difícil.', 2),
('72fe5f41-3d85-4421-ae61-1bdc63447dd5', 'Juntos', 'Pai, ajuda-nos a ser fiéis aos Teus princípios em todas as nossas decisões. Que a nossa vida mostre que Tua Palavra é a nossa maior honra.', 3),
('7345fbe9-a4fb-46ca-8006-a7c8101fc643', 'Pai', 'Senhor, ajuda meu filho a ter a coragem de Daniel e a não se dobrar diante das influências erradas. Que ele valorize a Tua Palavra acima de qualquer reconhecimento humano.', 1),
('7345fbe9-a4fb-46ca-8006-a7c8101fc643', 'Filho', 'Deus, dá-me sabedoria para decidir o que é certo antes que as tentações cheguem. Ajuda-me a ser firme nos meus valores, mesmo quando for difícil ser diferente.', 2),
('7345fbe9-a4fb-46ca-8006-a7c8101fc643', 'Juntos', 'Pai, nós Te pedimos um coração decidido e fiel. Que nossa família viva sempre de acordo com a Tua vontade, hoje e sempre.', 3),
('73d6c9cc-0777-48d0-acb1-f5c597640aea', 'Pai', 'Senhor, ajuda-me a guiar meu filho pelos caminhos da sabedoria. Que nossos olhos estejam sempre voltados para o que é reto.', 1),
('73d6c9cc-0777-48d0-acb1-f5c597640aea', 'Filho', 'Deus, dá-me inteligência para ignorar o que me afasta de Ti. Ajuda-me a cuidar do meu coração hoje.', 2),
('73d6c9cc-0777-48d0-acb1-f5c597640aea', 'Juntos', 'Pai, que nossas escolhas diárias nos mantenham firmes em Teus princípios. Que nossa atenção sempre Te honre.', 3),
('73ff69c4-fa8d-47cd-b21f-b3e93511c280', 'Pai', 'Senhor, ajuda-nos a valorizar a verdade acima de qualquer benefício próprio. Que a nossa honra seja sempre nossa maior riqueza.', 1),
('73ff69c4-fa8d-47cd-b21f-b3e93511c280', 'Filho', 'Pai, dá-me coragem para ser honesto mesmo quando for difícil ou quando ninguém estiver olhando. Quero que meu nome reflita Tua luz.', 2),
('73ff69c4-fa8d-47cd-b21f-b3e93511c280', 'Juntos', 'Que a nossa família seja conhecida pela retidão em tudo o que fizermos. Amém.', 3),
('747275e6-d168-47f7-92f5-514ea232f53b', 'Pai', 'Senhor, ajuda-me a ser um exemplo de lealdade e moderação para meus filhos. Que possamos honrar o Teu nome em cada escolha escondida.', 1),
('747275e6-d168-47f7-92f5-514ea232f53b', 'Filho', 'Deus, dá-me coragem para manter meus valores mesmo quando ninguém estiver me vendo. Que minhas amizades sejam firmadas no Teu temor.', 2),
('747275e6-d168-47f7-92f5-514ea232f53b', 'Juntos', 'Que a nossa casa seja um lugar de verdade e integridade diante de Ti. Que nossas ações revelem sempre o Teu caráter, amém.', 3),
('74b5746e-a785-4e66-8293-054823e39cd6', 'Pai', 'Senhor, ajuda-nos a ensinar nossos filhos a escolherem o Teu caminho. Que nossa casa seja um lugar de obediência e alegria.', 1),
('74b5746e-a785-4e66-8293-054823e39cd6', 'Filho', 'Papai do Céu, me ajude a ser corajoso como Daniel. Quero sempre fazer o que é certo, mesmo quando ninguém estiver olhando.', 2),
('74b5746e-a785-4e66-8293-054823e39cd6', 'Juntos', 'Obrigado, Deus, porque o Senhor cuida de nós em todos os momentos. Que o nosso serviço Te traga muita alegria, amém!', 3),
('74c4564b-ba5b-4c77-b74f-3dbf547f4b82', 'Pai', 'Senhor, ajuda-me a ser um exemplo de retidão e verdade para o meu filho. Que a minha vida seja coerente em todos os lugares.', 1),
('74c4564b-ba5b-4c77-b74f-3dbf547f4b82', 'Filho', 'Deus, dá-me coragem para escolher o caminho correto quando estiver sozinho. Que a minha consciência seja sempre guiada por Ti.', 2),
('74c4564b-ba5b-4c77-b74f-3dbf547f4b82', 'Juntos', 'Pai, que a nossa família seja reconhecida pela integridade. Que a nossa vida privada glorifique o Teu nome em tudo.', 3),
('74c76889-3ea6-427f-a36a-a22076cb6844', 'Pai', 'Senhor, dá a nós a mesma firmeza desses jovens. Que nossa família aprenda a Te obedecer acima de qualquer pressão.', 1),
('74c76889-3ea6-427f-a36a-a22076cb6844', 'Filho', 'Pai Celestial, ajuda-me a manter meus valores firmes na escola e entre meus amigos. Que eu não tenha medo de dizer a verdade.', 2),
('74c76889-3ea6-427f-a36a-a22076cb6844', 'Juntos', 'Que a nossa casa seja um lugar de obediência a Ti. Que a nossa vida glorifique o Teu nome em cada escolha.', 3),
('75235c01-a1ee-4bb3-b66e-cc902753707e', 'Pai', 'Senhor, ajuda-me a ser um exemplo de lealdade para meu filho, guiando-o a buscar amizades que honrem o Teu nome. Que sejamos uma família que valoriza o caráter acima das conveniências do mundo.', 1),
('75235c01-a1ee-4bb3-b66e-cc902753707e', 'Filho', 'Deus, dá-me sabedoria para escolher bem aqueles com quem ando. Que eu aprenda com Jônatas a ser um amigo fiel, honesto e que busca o Teu querer.', 2),
('75235c01-a1ee-4bb3-b66e-cc902753707e', 'Juntos', 'Pai, que a nossa casa seja um refúgio de amizades verdadeiras e sinceras. Que possamos sempre nos fortalecer na caminhada rumo ao Teu Reino, amém.', 3),
('75e7eba6-113d-4574-a9b9-37ce62956876', 'Individual', 'Senhor, concede-me a sabedoria para desfrutar das tuas bênçãos com gratidão, mas sem a ganância que corrompe. Que o meu coração aprenda a encontrar satisfação na medida certa, e que eu tenha a força para frear meus apetites antes que eles se tornem senhores sobre mim. Que a minha vida reflita o domínio próprio que vem do teu Espírito. Amém.', 1),
('76097aa2-11c3-4ad8-84fd-2412c5cb82d4', 'Pai', 'Senhor, ajuda-nos a confiar no Teu poder como Davi confiou no campo. Que possamos ensinar aos nossos filhos que o Teu auxílio é real.', 1),
('76097aa2-11c3-4ad8-84fd-2412c5cb82d4', 'Filho', 'Deus, quando eu sentir medo das provas ou de não ser aceito, traz à minha memória que Tu estiveste comigo antes. Ajuda-me a ser forte.', 2),
('76097aa2-11c3-4ad8-84fd-2412c5cb82d4', 'Juntos', 'Pai, obrigado porque nenhum gigante é maior que a Tua proteção. Confiamos que o Senhor vence nossas batalhas todos os dias.', 3),
('764fad17-48f4-46d1-8748-6535f812a51e', 'Pai', 'Pai do Céu, ensina-nos a perdoar nossos amigos com a mesma alegria do pai da história. Que o nosso amor seja sempre maior que qualquer erro.', 1),
('764fad17-48f4-46d1-8748-6535f812a51e', 'Filho', 'Jesus, ajuda-me a ter coragem de pedir desculpas quando eu fizer algo errado. Quero ser um bom amigo como Tu és comigo.', 2),
('764fad17-48f4-46d1-8748-6535f812a51e', 'Juntos', 'Obrigado, Deus, pelo Teu amor que nos traz de volta. Ajuda nossa família a viver sempre unida e com o coração perdoador.', 3),
('76af388b-e478-47f4-8a26-36231b26c044', 'Pai', 'Pai do céu, ajuda-nos a ser bons exemplos para nossos filhos. Que nossas amizades sempre apontem para o Teu amor.', 1),
('76af388b-e478-47f4-8a26-36231b26c044', 'Filho', 'Querido Deus, ensina-me a escolher amigos que gostam de orar e de brincar com bondade. Quero seguir o Teu caminho.', 2),
('76af388b-e478-47f4-8a26-36231b26c044', 'Juntos', 'Senhor, abençoa as nossas amizades para que cresçamos sempre em sabedoria e alegria. Amém!', 3),
('770d009a-2ed1-4bf6-bfce-538dd4285c3b', 'Individual', 'Senhor, peço discernimento para selecionar as vozes que permito habitar minha mente. Ajuda-me a caminhar com os sábios e a manter a fidelidade aos Teus princípios, para que minhas decisões sejam guiadas pela Tua verdade e não pela opinião dos homens.', 1),
('77e5fa17-9972-43b8-abaa-b0636d4a4643', 'Pai', 'Senhor, ajuda-me a ser um exemplo de obediência e firmeza para meus filhos. Que possamos ver a Tua mão em cada pequeno passo de fé.', 1),
('77e5fa17-9972-43b8-abaa-b0636d4a4643', 'Filho', 'Deus, dá-me coragem para escolher o que é certo, mesmo quando estiver difícil. Ajuda-me a confiar em Ti acima da opinião dos meus amigos.', 2),
('77e5fa17-9972-43b8-abaa-b0636d4a4643', 'Juntos', 'Pai, que nossa casa seja um lugar de fé real e ações sinceras. Que possamos construir juntos uma vida que Te agrade sempre.', 3),
('77f9ce04-5cc1-4ddd-8cbc-d9ad874b75da', 'Pai', 'Senhor, ajuda-nos a lembrar que Tua presença é real em cada cômodo da nossa casa. Ensina-nos a viver com honestidade em todos os momentos.', 1),
('77f9ce04-5cc1-4ddd-8cbc-d9ad874b75da', 'Filho', 'Deus, perdoa-me quando tento parecer melhor do que realmente sou. Ajuda-me a ser verdadeiro, mesmo quando ninguém estiver olhando para mim.', 2),
('77f9ce04-5cc1-4ddd-8cbc-d9ad874b75da', 'Juntos', 'Que a nossa família busque sempre a Tua verdade, pois o Teu olhar é o que mais importa para nós. Amém.', 3),
('77fb9fb5-5a9f-4b5e-9512-841099da434b', 'Pai', 'Papai do Céu, ensina meus filhos a confiarem no Teu bom caminho. Ajuda-os a entender que o nosso cuidado é um reflexo do Teu amor por nós.', 1),
('77fb9fb5-5a9f-4b5e-9512-841099da434b', 'Filho', 'Querido Deus, ajuda-me a obedecer com alegria, igual ao Noé. Quero ser um bom ouvinte da Tua voz e das ordens de quem cuida de mim.', 2),
('77fb9fb5-5a9f-4b5e-9512-841099da434b', 'Juntos', 'Obrigado, Senhor, porque Tua obediência nos mantém seguros. Queremos caminhar sempre contigo, confiando em Teu cuidado todos os dias.', 3),
('7805fa89-2492-4d6d-a648-789f00885226', 'Individual', 'Senhor, ensina-me a exercer a bondade como um dever de fidelidade e não como uma troca de favores. Que minha vida reflita a misericórdia que recebi de Ti, levando-me a honrar os esquecidos e a servir com integridade, mesmo quando ninguém estiver observando. Amém.', 1),
('7813cad2-e5b7-4805-b3d8-034015eb6432', 'Pai', 'Senhor, ajuda-nos a governar nossa fala com a Tua sabedoria. Que nossos lábios sejam fontes de bênçãos para nossa família.', 1),
('7813cad2-e5b7-4805-b3d8-034015eb6432', 'Filho', 'Pai Celestial, perdoa-me pelas vezes em que usei mal as minhas palavras. Ensina-me a falar a verdade com amor e respeito.', 2),
('7813cad2-e5b7-4805-b3d8-034015eb6432', 'Juntos', 'Que a nossa casa seja um lugar onde as palavras tragam vida. Que o Senhor guie nossa comunicação todos os dias.', 3),
('7837efe4-1767-4079-920e-4e5cb2957358', 'Individual', 'Senhor, perdoa-me por olhar para os gigantes da minha vida e esquecer que Tu és o Deus que governa todas as coisas. Remove o medo que me impede de avançar e concede-me um coração corajoso e fiel. Que a minha interpretação dos fatos seja sempre alinhada com a Tua promessa, e que eu tenha a prontidão necessária para agir conforme a Tua vontade, sem retroceder diante das dificuldades. Amém.', 1),
('7854d7d8-e478-4f91-9496-4d5eef1663c5', 'Pai', 'Senhor, ajuda-nos a ter a mesma firmeza de Daniel em nossa casa. Que possamos ensinar nossos filhos a valorizarem a Tua vontade acima da aprovação das pessoas.', 1),
('7854d7d8-e478-4f91-9496-4d5eef1663c5', 'Filho', 'Deus, dá-me coragem para escolher o que é certo, mesmo quando meus amigos estiverem fazendo o contrário. Que eu seja firme nas minhas convicções.', 2),
('7854d7d8-e478-4f91-9496-4d5eef1663c5', 'Juntos', 'Pai, ajuda nossa família a ser fiel a Ti em todos os lugares. Que a Tua verdade seja sempre o nosso guia.', 3),
('786396b9-4eba-418b-b6ae-3c61b1d35f41', 'Pai', 'Senhor, ensina-nos a enxergar com os Teus olhos. Que nossa família aprenda a dar com alegria o que nos é precioso.', 1),
('786396b9-4eba-418b-b6ae-3c61b1d35f41', 'Filho', 'Deus, ajuda-me a ser generoso mesmo quando for difícil ou quando eu quiser guardar tudo para mim. Que meu coração seja grato.', 2),
('786396b9-4eba-418b-b6ae-3c61b1d35f41', 'Juntos', 'Que a nossa vida seja uma oferta sincera e completa a Ti, Senhor. Amém.', 3),
('7871b353-4849-45e0-9dc3-b3b2b18b94c1', 'Pai', 'Papai do céu, obrigado por nos dar o fôlego de vida hoje. Ensina-nos a ver Tua bondade em todas as coisas.', 1),
('7871b353-4849-45e0-9dc3-b3b2b18b94c1', 'Filho', 'Obrigado, Deus, por cada coisa linda que criaste. Quero cantar e Te agradecer com todo o meu coração.', 2),
('7871b353-4849-45e0-9dc3-b3b2b18b94c1', 'Juntos', 'Senhor, que nosso louvor suba até Ti como um presente especial. Amém!', 3),
('78cfa45a-bfba-4623-b213-c41d107cec82', 'Pai', 'Senhor, dá a nós a coragem de Sadraque, Mesaque e Abednego para nunca dobrar nossos joelhos diante dos ídolos desta geração. Que nossa casa seja um lugar onde a verdade de Deus é a autoridade final.', 1),
('78cfa45a-bfba-4623-b213-c41d107cec82', 'Filho', 'Pai celestial, ajuda-me a ser firme em minhas escolhas quando estiver com meus amigos. Que eu priorize a Tua vontade acima da aprovação daqueles que me rodeiam.', 2),
('78cfa45a-bfba-4623-b213-c41d107cec82', 'Juntos', 'Deus eterno, guiai nossos passos e fortalecei nossa fé. Que o nosso único propósito seja honrar a Ti em cada decisão que tomarmos hoje e sempre.', 3),
('78fecbc9-eb53-4263-833b-523deb185133', 'Individual', 'Senhor, ajuda-me a manter os meus olhos fixos no Teu caminho. Que a minha visão não se perca em distrações que afastam o meu coração da Tua vontade. Dá-me disciplina para guiar os meus passos com retidão e integridade em cada decisão que eu tomar hoje. Amém.', 1),
('7923717e-11ca-4395-9c71-8eafa601084e', 'Individual', 'Senhor, ajuda-me a edificar um caráter que não oscila diante das exigências deste mundo. Que a minha devoção a Ti seja tão profunda que, mesmo no fogo das provações, minha decisão de Te servir permaneça inabalável. Ensina-me a priorizar a Tua vontade acima do meu próprio bem-estar e a agir com integridade, sabendo que a minha vida pertence somente a Ti.', 1),
('7995c480-bd3c-4784-95c7-6dc6359d9f71', 'Pai', 'Senhor, ajuda-nos a ser fiéis como Daniel foi na Babilônia. Que possamos sempre escolher o Teu caminho acima de tudo.', 1),
('7995c480-bd3c-4784-95c7-6dc6359d9f71', 'Filho', 'Papai do Céu, me ajude a ser obediente e corajoso. Quero ser forte como Daniel e fazer o que é certo.', 2),
('7995c480-bd3c-4784-95c7-6dc6359d9f71', 'Juntos', 'Obrigado, Deus, por cuidar de nós em todo o tempo. Ajude nossa família a Te amar e obedecer sempre, amém.', 3),
('79a64901-f56d-46c4-a178-e88248b2158a', 'Individual', 'Senhor, perdoa-me pelas vezes em que minha agenda ocupou o lugar da Tua misericórdia. Capacita-me a ser um instrumento de alívio e cuidado, agindo com fidelidade e prontidão diante do sofrimento alheio. Que minhas mãos sejam instrumentos do Teu amor, sem hesitação e sem esperar retribuição. Amém.', 1),
('79a6d874-c0ab-4e61-be85-0ab5156ab462', 'Pai', 'Senhor, ajuda-nos a ensinar nossos filhos a observar o Teu caminho. Dá-nos paciência para guiar seus passos com a Tua sabedoria.', 1),
('79a6d874-c0ab-4e61-be85-0ab5156ab462', 'Filho', 'Papai do Céu, me ajuda a parar e pensar antes de agir. Quero ser prudente como a formiguinha e aprender com o Senhor.', 2),
('79a6d874-c0ab-4e61-be85-0ab5156ab462', 'Juntos', 'Obrigado, Deus, por Tua Palavra que ilumina nossa caminhada. Queremos sempre escolher o caminho que agrada ao Teu coração!', 3),
('79aa98da-071b-41c9-a99f-a9d85614bd12', 'Individual', 'Senhor, que a minha fidelidade não dependa da abundância ou da facilidade, mas da Tua soberania. Dá-me forças para permanecer firme em Teus caminhos, mesmo quando a dor ou a perda tentarem me desviar. Que minha vida seja um testemunho de integridade, reconhecendo que tudo o que sou e tenho pertence ao Teu cuidado. Amém.', 1),
('79fc425b-c100-46c7-b737-ec989ef0403b', 'Pai', 'Senhor, ajuda-nos a ensinar aos nossos filhos o valor de um caráter inegociável. Que a Tua Palavra seja o guia das nossas decisões em casa.', 1),
('79fc425b-c100-46c7-b737-ec989ef0403b', 'Filho', 'Pai do céu, dá-me coragem para dizer não ao que me afasta de Ti. Quero ser firme em minhas escolhas, mesmo quando ninguém estiver vendo.', 2),
('79fc425b-c100-46c7-b737-ec989ef0403b', 'Juntos', 'Deus, ajuda-nos a crescer em sabedoria e moderação. Que a nossa vida seja um testemunho da Tua verdade em todos os lugares.', 3),
('7a4cfeee-8e63-4ae9-9aff-8f915de3f23c', 'Pai', 'Pai do Céu, obrigado porque Tu és a luz que nos guia. Ajuda meu filho a confiar em Ti quando estiver triste.', 1),
('7a4cfeee-8e63-4ae9-9aff-8f915de3f23c', 'Filho', 'Papai do Céu, por favor, me dê forças para levantar quando eu cair. Obrigado por segurar minha mão sempre.', 2),
('7a4cfeee-8e63-4ae9-9aff-8f915de3f23c', 'Juntos', 'Obrigado, Deus, porque nunca estamos sozinhos. Com o Teu amor, aprendemos a ser fortes todos os dias.', 3),
('7b2aa24a-a751-4c1f-afa6-69e36d72b0ec', 'Pai', 'Senhor, ajuda-me a ensinar o valor da palavra cumprida e da retidão aos meus filhos. Que o meu exemplo dentro de casa reflita o Teu temor.', 1),
('7b2aa24a-a751-4c1f-afa6-69e36d72b0ec', 'Filho', 'Deus, dá-me coragem para ser um amigo fiel e leal, mesmo quando for difícil. Que minhas escolhas privadas sejam sempre honestas diante de Ti.', 2),
('7b2aa24a-a751-4c1f-afa6-69e36d72b0ec', 'Juntos', 'Pai, fortalece nossa casa na aliança contigo. Que possamos sempre sustentar uns aos outros com verdade e honra em todas as estações.', 3),
('7b46a907-f9d1-4ee1-8fdb-89b83801cf5c', 'Pai', 'Senhor, ajuda-me a guiar meu filho com sabedoria, lembrando-o de que o Teu olhar é o que realmente importa. Que a nossa casa seja um lugar de verdade absoluta.', 1),
('7b46a907-f9d1-4ee1-8fdb-89b83801cf5c', 'Filho', 'Deus, guarda o meu coração de pensamentos e ações que me afastam da Tua vontade. Ajuda-me a ser fiel mesmo quando ninguém estiver me vendo.', 2),
('7b46a907-f9d1-4ee1-8fdb-89b83801cf5c', 'Juntos', 'Pai, que nossas escolhas diárias sejam sempre retas e honrem o Teu nome. Fortalece o nosso caráter para seguirmos somente o Teu caminho.', 3),
('7b5b6d55-dee1-4f19-b86c-0ac9b0d74c69', 'Pai', 'Senhor, ajuda-me a ser um porto seguro para meu filho. Que ele encontre em mim apoio para confessar suas falhas sem medo.', 1),
('7b5b6d55-dee1-4f19-b86c-0ac9b0d74c69', 'Filho', 'Pai Celestial, dá-me a coragem de ser honesto sobre meus erros. Não quero esconder minhas falhas, mas buscar sempre o caminho da verdade.', 2),
('7b5b6d55-dee1-4f19-b86c-0ac9b0d74c69', 'Juntos', 'Deus, ensina-nos a valorizar a verdade acima de nossa própria imagem. Que nossa casa seja sempre um lugar de perdão e restauração.', 3),
('7b9a0304-4555-4ca2-afe6-72983076fb26', 'Individual', 'Senhor, ajuda-me a não ser um homem de memória curta. Que o Teu agir no passado seja a base sólida da minha confiança hoje, impedindo que a rebeldia ou a ingratidão ganhem espaço no meu coração. Que eu seja fiel em transmitir Tua verdade e que minha vida reflita um caráter forjado pelo reconhecimento constante do Teu cuidado.', 1),
('7be6be34-7a90-4f49-bece-2b25297b5ef5', 'Pai', 'Senhor, dá ao meu filho um olhar puro e discernimento para enxergar além das aparências. Que ele busque o Teu caminho em todas as suas escolhas.', 1),
('7be6be34-7a90-4f49-bece-2b25297b5ef5', 'Filho', 'Pai celestial, ajuda-me a não ser seduzido pelo que é apenas atraente aos olhos. Que a Tua Palavra seja o guia do que eu contemplo.', 2),
('7be6be34-7a90-4f49-bece-2b25297b5ef5', 'Juntos', 'Que a nossa família escolha a Tua presença acima de qualquer vantagem terrena. Fortalece-nos para caminharmos na Tua verdade, hoje e sempre.', 3),
('7c265c2e-b7e5-4a1f-a563-b76f176c5796', 'Pai', 'Senhor, ensina-me a ser um exemplo de serviço humilde para os meus filhos. Que meu trabalho diário seja uma entrega feita para Ti e não para os homens.', 1),
('7c265c2e-b7e5-4a1f-a563-b76f176c5796', 'Filho', 'Pai do céu, ajuda-me a buscar a Tua aprovação em vez de aplausos. Que eu aprenda a servir com alegria, mesmo nas tarefas que ninguém valoriza.', 2),
('7c265c2e-b7e5-4a1f-a563-b76f176c5796', 'Juntos', 'Deus, transforma nosso lar em um lugar de serviço mútuo. Que as nossas escolhas sejam sempre guiadas pelo exemplo de Jesus, nosso Mestre e Salvador.', 3),
('7c485c31-3d4c-4a3d-ad4f-d0c2264af97e', 'Pai', 'Senhor, ajuda-nos a valorizar mais a integridade do que qualquer ganho passageiro. Que nossa família busque a Tua sabedoria em todas as decisões.', 1),
('7c485c31-3d4c-4a3d-ad4f-d0c2264af97e', 'Filho', 'Deus, dá-me coragem para ser verdadeiro na escola e com meus amigos. Que o meu caráter reflita o Teu ensinamento todos os dias.', 2),
('7c485c31-3d4c-4a3d-ad4f-d0c2264af97e', 'Juntos', 'Pai, guia nossos passos para que o nosso nome seja um testemunho da Tua verdade. Que nossa vida seja preciosa aos Teus olhos.', 3),
('7c55213d-e958-45f2-b174-6f2eab7e85a2', 'Pai', 'Senhor, ajuda-me a ser um exemplo de lealdade para meu filho. Que possamos valorizar amigos que honram a Tua Palavra.', 1),
('7c55213d-e958-45f2-b174-6f2eab7e85a2', 'Filho', 'Deus, dá-me sabedoria para escolher bem minhas amizades. Que eu saiba reconhecer e nutrir relacionamentos baseados na verdade.', 2),
('7c55213d-e958-45f2-b174-6f2eab7e85a2', 'Juntos', 'Pai, faz de nossa família um lugar de pactos verdadeiros. Que nossas amizades externas sejam firmadas no Teu temor e propósito.', 3),
('7cbc0c43-4316-453b-bcfe-e8568e7ba8cc', 'Pai', 'Senhor, dá ao meu filho a coragem de Daniel para honrar a Tua lei. Que ele saiba dizer não quando o mundo oferecer algo contrário à Tua vontade.', 1),
('7cbc0c43-4316-453b-bcfe-e8568e7ba8cc', 'Filho', 'Pai celestial, ajuda-me a ser firme em minhas escolhas e a não me deixar levar pela pressão dos meus amigos. Fortalece o meu coração para Te obedecer sempre.', 2),
('7cbc0c43-4316-453b-bcfe-e8568e7ba8cc', 'Juntos', 'Que a nossa família permaneça fiel aos Teus mandamentos, independentemente do que o mundo proponha. Ajuda-nos a sermos luz e exemplo onde quer que estejamos.', 3),
('7d22eb1e-ce44-499b-ad29-38ef2d6285aa', 'Individual', 'Senhor, ajuda-me a buscar Tua face antes de tentar resolver conflitos terrenos. Que a Tua paz guie minhas ações e que eu tenha a coragem de ser o primeiro a estender a mão, abandonando o orgulho e a necessidade de justificativa para viver a reconciliação que o Senhor deseja para mim.', 1),
('7d281415-784a-41eb-8202-7a92e21d21c6', 'Pai', 'Senhor, peço que concedas aos meus filhos a mesma prudência que deste a Salomão. Que a sabedoria divina guie seus passos desde cedo.', 1),
('7d281415-784a-41eb-8202-7a92e21d21c6', 'Filho', 'Deus, ajuda-me a escolher o certo, mesmo quando ninguém estiver vendo. Que meu coração busque a Tua justiça acima dos meus desejos.', 2),
('7d281415-784a-41eb-8202-7a92e21d21c6', 'Juntos', 'Pedimos, ó Deus, um coração compreensivo para seguirmos Teus caminhos. Que a nossa casa seja um lugar de escolhas sábias.', 3),
('7d320e8d-03cc-4aff-9f64-947ef77f328c', 'Pai', 'Senhor, ajuda-nos a ter a coragem de reconhecer nossos erros. Que nossa casa seja sempre um lugar de verdade e acolhimento.', 1),
('7d320e8d-03cc-4aff-9f64-947ef77f328c', 'Filho', 'Pai do céu, perdoa-me quando tento esconder minhas falhas. Dá-me forças para ser honesto e íntegro em tudo o que fizer.', 2),
('7d320e8d-03cc-4aff-9f64-947ef77f328c', 'Juntos', 'Obrigado, Deus, pelo teu amor que nos recebe de braços abertos. Queremos caminhar sempre na tua presença, aprendendo a obedecer.', 3),
('7d5a3b88-0d80-4b76-a06b-a12e411b6be5', 'Pai', 'Senhor, obrigado porque Tu sempre aguardas o nosso retorno de braços abertos. Ensina-nos a perdoar nossos filhos da mesma forma que Tu nos perdoas.', 1),
('7d5a3b88-0d80-4b76-a06b-a12e411b6be5', 'Filho', 'Pai do céu, ajuda-me a ser honesto quando eu errar e a não ter medo de voltar atrás. Dá-me coragem para assumir minhas falhas hoje.', 2),
('7d5a3b88-0d80-4b76-a06b-a12e411b6be5', 'Juntos', 'Que a nossa casa seja sempre um lugar de perdão e verdade. Ajuda-nos a caminhar sempre mais perto de Ti, juntos.', 3),
('7d5cbc8c-b05c-4558-89c2-179336bac6bf', 'Pai', 'Senhor, ensina nosso filho a ter a coragem de Daniel para escolher sempre o Teu caminho. Que ele aprenda a ouvir a Tua voz acima de todas as outras.', 1),
('7d5cbc8c-b05c-4558-89c2-179336bac6bf', 'Filho', 'Papai do céu, me ajuda a ser obediente igual ao Daniel. Me dê forças para escolher o que é certo, mesmo quando for difícil.', 2),
('7d5cbc8c-b05c-4558-89c2-179336bac6bf', 'Juntos', 'Obrigado, Deus, porque o Senhor cuida de nós em todos os lugares. Que a nossa família caminhe sempre com firmeza seguindo a Sua vontade.', 3),
('7d7bc14b-0f46-4b7a-979e-7ca46c8931f3', 'Pai', 'Papai do Céu, obrigado porque o Senhor sempre nos recebe com amor. Ajuda-nos a sermos bondosos uns com os outros.', 1),
('7d7bc14b-0f46-4b7a-979e-7ca46c8931f3', 'Filho', 'Jesus, me desculpe pelas vezes que não fui obediente. Quero ter um coração alegre e perdoador como o do pai da história.', 2),
('7d7bc14b-0f46-4b7a-979e-7ca46c8931f3', 'Juntos', 'Obrigado, Deus, por nos amar tanto. Ensina a nossa família a sempre começar de novo com amor.', 3),
('7dd8f554-0349-47c3-9646-db5e59974d23', 'Pai', 'Senhor, ajuda-me a guiar meu filho para que ele tenha sabedoria na escolha dos seus amigos. Que ele encontre pessoas que somem para o seu bem.', 1),
('7dd8f554-0349-47c3-9646-db5e59974d23', 'Filho', 'Deus, dá-me coragem para permanecer fiel aos meus valores, mesmo quando for difícil. Ajuda-me a ser um exemplo positivo para aqueles que caminham comigo.', 2),
('7dd8f554-0349-47c3-9646-db5e59974d23', 'Juntos', 'Pai, protege nosso coração e nossa mente das influências ruins. Fortalece nossa união e nossa fidelidade aos Teus ensinamentos todos os dias.', 3),
('7df93031-75a5-4b6f-b11b-9c419d541f14', 'Pai', 'Pai do Céu, obrigado porque o Teu amor é maior que os nossos erros. Ensina-nos a ter corações sinceros e prontos para o perdão.', 1),
('7df93031-75a5-4b6f-b11b-9c419d541f14', 'Filho', 'Querido Deus, quando eu desobedecer, ajuda-me a não ter medo e a pedir perdão logo. Eu quero sempre andar pertinho de Ti.', 2),
('7df93031-75a5-4b6f-b11b-9c419d541f14', 'Juntos', 'Obrigado por sermos uma família que se ama e se perdoa. Ajuda-nos a recomeçar todos os dias com alegria!', 3),
('7e37095d-214a-46c7-8e1d-84f2202ba8ad', 'Pai', 'Senhor, ensina-me a guiar meu filho no caminho do equilíbrio. Ajuda-nos a reconhecer que a verdadeira força vem do autocontrole.', 1),
('7e37095d-214a-46c7-8e1d-84f2202ba8ad', 'Filho', 'Deus, dá-me sabedoria para medir minhas escolhas. Que eu saiba parar no momento certo e honrar Teu nome em tudo.', 2),
('7e37095d-214a-46c7-8e1d-84f2202ba8ad', 'Juntos', 'Pai, ajuda-nos a construir uma vida pautada na moderação. Que nossa casa seja um exemplo de integridade e domínio próprio.', 3),
('7e940f27-bca8-41b2-8a7e-c3b9ea52fa02', 'Individual', 'Senhor, reconheço que muitas vezes ocultei minhas falhas atrás de desculpas e silêncio. Hoje, coloco meu orgulho diante de Ti e confesso que errei. Limpa o meu coração de toda dissimulação e concede-me um espírito pronto para a verdade, para que eu caminhe na Tua luz com integridade e fidelidade. Amém.', 1),
('7ec05866-321e-4675-a94b-f32eec58fcca', 'Individual', 'Senhor, perdoa-me pela hesitação em seguir Tua voz quando não compreendo o destino. Fortalece minha vontade para que eu abandone as seguranças que me prendem e caminhe com convicção, sabendo que Teu chamado é o mapa suficiente para os meus dias. Que minha obediência seja prática, imediata e fiel, honrando a Tua direção acima dos meus medos. Amém.', 1),
('7f395662-8ea3-41bb-96b2-dced21812183', 'Pai', 'Papai do Céu, ajuda-nos a ter um coração bondoso para perdoar quem nos entristece. Que a nossa família seja sempre um lugar de paz.', 1),
('7f395662-8ea3-41bb-96b2-dced21812183', 'Filho', 'Querido Deus, ajuda-me a pedir perdão quando eu errar. Quero ser amigo de todos e ter o coração cheio de alegria.', 2),
('7f395662-8ea3-41bb-96b2-dced21812183', 'Juntos', 'Obrigado por nos ensinar a fazer as pazes. Amém!', 3),
('7f4f2f14-bdb6-4a81-bbfd-c05f8cdc4402', 'Individual', 'Senhor, reconheço que tenho permitido que medos se tornem gigantes diante dos meus olhos, paralisando a obediência que te devo. Remove a névoa da dúvida que me impede de agir com integridade e coragem. Fortalece o meu espírito para que, em vez de recuar perante as dificuldades, eu possa caminhar com firmeza, confiando na Tua soberania acima de qualquer circunstância que hoje me intimida. Amém.', 1),
('7fd5c387-118e-494e-8480-0ce0aa1b8e07', 'Individual', 'Senhor, ajuda-me a enxergar as minhas falhas com a mesma lucidez que o filho pródigo teve. Que a minha comunicação seja marcada pela verdade e pela ausência de orgulho, permitindo que eu assuma meus erros com coragem para que o Teu perdão restaure a retidão do meu caráter. Amém.', 1),
('80263e92-fa5d-4378-bb3a-48ea35898cca', 'Individual', 'Senhor, reconheço que muitas vezes me afastei do Teu propósito por orgulho. Concede-me a coragem de abandonar minhas justificativas, de levantar-me da minha desobediência e de caminhar, sem reservas, de volta à Tua presença e ao Teu caminho reto.', 1),
('802b3148-7872-41a5-ab88-2b23defc8281', 'Pai', 'Senhor, ensina-nos a olhar para as pessoas com os Teus olhos. Que nossa família nunca seja indiferente à dor do próximo.', 1),
('802b3148-7872-41a5-ab88-2b23defc8281', 'Filho', 'Deus, dá-me coragem para ajudar quem precisa. Que eu não tenha medo de fazer o bem mesmo se ninguém mais fizer.', 2),
('802b3148-7872-41a5-ab88-2b23defc8281', 'Juntos', 'Pai, faz de nossa casa um lugar de amor e serviço. Que sejamos instrumentos da Tua compaixão todos os dias.', 3),
('81a7c719-050e-408b-b8b7-4ac0f70200d3', 'Pai', 'Senhor, dá aos nossos filhos a mesma coragem que deste aos três jovens hebreus. Que eles saibam priorizar a Tua verdade diante de qualquer pressão.', 1),
('81a7c719-050e-408b-b8b7-4ac0f70200d3', 'Filho', 'Pai do céu, ajuda-me a não ter medo de fazer o que é certo. Dá-me firmeza para permanecer fiel a Ti, mesmo quando for difícil.', 2),
('81a7c719-050e-408b-b8b7-4ac0f70200d3', 'Juntos', 'Deus, que a nossa família seja sempre um lugar de lealdade a Ti. Que a Tua presença nos dê coragem em todos os dias.', 3),
('81f3a7cd-af8d-4e54-9df6-1a790450a4a6', 'Pai', 'Senhor, ensina nosso filho a ser firme em seus princípios como Daniel foi. Que ele sempre busque Te agradar acima de tudo.', 1),
('81f3a7cd-af8d-4e54-9df6-1a790450a4a6', 'Filho', 'Papai do Céu, ajuda-me a dizer não para o que é errado. Quero ser forte e obediente como Daniel.', 2),
('81f3a7cd-af8d-4e54-9df6-1a790450a4a6', 'Juntos', 'Obrigado, Deus, por estares sempre conosco. Ajuda-nos a sermos fiéis ao Teu caminho em todos os nossos dias.', 3),
('821ee168-f16c-4112-95d4-c65d7a7bcf2f', 'Individual', 'Senhor, sonda meu coração e remove qualquer desejo de simulação ou engano. Concede-me a coragem da verdade e a integridade de viver diante de Ti com transparência, sem buscar o aplauso humano através de máscaras ou omissões.', 1),
('82bd7e8b-0066-4da0-8551-56747dbdcdda', 'Pai', 'Senhor, ensina meu filho a valorizar a constância e a honrar seus compromissos. Que ele aprenda a ser um alicerce firme em nossa família.', 1),
('82bd7e8b-0066-4da0-8551-56747dbdcdda', 'Filho', 'Deus, ajuda-me a escolher ser fiel, mesmo quando for difícil ou solitário. Que meu caráter seja íntegro em tudo o que eu fizer.', 2),
('82bd7e8b-0066-4da0-8551-56747dbdcdda', 'Juntos', 'Pai, fortalece nossa união e ensina-nos a caminhar juntos em Tua verdade. Que nossa casa seja um exemplo de lealdade e fé.', 3),
('82c1877d-1cec-4d5f-ad76-52f47a5e63bf', 'Pai', 'Papai do Céu, obrigado por cuidares de nós todos os dias. Ajuda-nos a confiar em Ti, mesmo quando o dia parecer triste.', 1),
('82c1877d-1cec-4d5f-ad76-52f47a5e63bf', 'Filho', 'Obrigado, Jesus, pelo teu amor e pelas coisas boas que recebi hoje. Ensina-me a ser sempre uma criança agradecida.', 2),
('82c1877d-1cec-4d5f-ad76-52f47a5e63bf', 'Juntos', 'Deus, nosso Pai, obrigado por estares sempre conosco. Queremos Te amar de todo o coração, hoje e sempre!', 3),
('82e5f32f-f8b1-4248-91c8-5982e1f1c08c', 'Pai', 'Papai do Céu, obrigado porque Tu sempre nos esperas de braços abertos. Ensina-nos a ter um coração humilde para reconhecer quando erramos.', 1),
('82e5f32f-f8b1-4248-91c8-5982e1f1c08c', 'Filho', 'Jesus, ajuda-me a ser corajoso para pedir desculpas quando eu desobedecer. Quero sempre voltar para o Teu abraço de amor.', 2),
('82e5f32f-f8b1-4248-91c8-5982e1f1c08c', 'Juntos', 'Obrigado por sermos uma família que se perdoa. Que o Teu amor nos guie em todos os nossos dias, amém!', 3),
('83795294-31aa-4f70-b26a-cc477479c295', 'Pai', 'Papai do céu, ajuda-nos a ser uma família que escolhe sempre a paz. Que o nosso lar seja um lugar de amor e paciência.', 1),
('83795294-31aa-4f70-b26a-cc477479c295', 'Filho', 'Jesus, ensina o meu coração a ser manso como o Teu. Ajuda-me a usar minhas mãos para abraçar e fazer as pazes.', 2),
('83795294-31aa-4f70-b26a-cc477479c295', 'Juntos', 'Obrigado, Senhor, por nos chamar de Teus filhos. Que a Tua paz brilhe em nossa casa hoje e sempre.', 3),
('83ee85a4-dccb-422f-bc68-f259336f058c', 'Pai', 'Senhor, ajuda-me a educar meus filhos com sabedoria. Que eles encontrem em Ti a força para serem fiéis em todo o tempo.', 1),
('83ee85a4-dccb-422f-bc68-f259336f058c', 'Filho', 'Deus, dá-me coragem para seguir os Teus mandamentos, mesmo quando ninguém estiver olhando. Ensina-me a ser firme como Daniel.', 2),
('83ee85a4-dccb-422f-bc68-f259336f058c', 'Juntos', 'Pai, que nossa família sempre escolha a Tua vontade acima de qualquer conveniência. Que sejamos sempre fiéis ao Senhor.', 3);
